configuration.jsScript:
// 1. CAZADOR DE VARIABLES: Buscamos el tipo de alarma directo en el "msg" primero
var tipo_falla = msg.type || msg.name || metadata.alarmType || metadata.type || "Anomalía No Identificada";

// 2. Definimos el esqueleto del mensaje
var texto_mensaje = "🚨 ALERTA CRÍTICA SCADA (OSM27) 🚨\n\n";

// 3. Lógica condicional mapeada
switch (tipo_falla) {
    case "Alarma de Cortocircuito":
        texto_mensaje += "⚡ EVENTO: Cortocircuito detectado (Sobrecorriente).\n⚠️ Las corrientes de fase superaron los 300A nominales. El reconectador inicia ciclo de apertura para proteger la red.";
        break;

    case "Alarma de SAG":
        texto_mensaje += "📉 ALERTA: Hueco de Tensión / SAG detectado.\n⚠️ El voltaje RMS ha caído por debajo de 11.22 kV en media tensión. Monitoreando estabilidad de carga.";
        break;

    case "Alarma de Bloqueo":
        texto_mensaje += "🛑 BLOQUEO TOTAL: LOCKOUT (ANSI 79).\n❌ Falla permanente en la línea. El equipo agotó sus 3 reintentos de cierre automático. Requiere patrullaje de cuadrilla y RESET manual.";
        break;

    case "Alarma de Equipo Abierto":
        texto_mensaje += "🔓 AVISO: El reconectador se ha ABIERTO.\nℹ️ La línea se encuentra desenergizada.";
        break;

    case "Alarma de Equipo Cerrado":
        texto_mensaje += "✅ AVISO: El reconectador se ha CERRADO.\n⚡ El circuito está energizado y operando con normalidad.";
        break;

    default:
        texto_mensaje += "ℹ️ AVISO: Registro de evento de red no indexado: [" + tipo_falla + "]";
}

// 4. Parche de Zona Horaria (UTC-3 para Argentina)
var fecha_actual = new Date();
// Restamos 3 horas exactas para compensar el UTC por defecto del servidor
fecha_actual.setHours(fecha_actual.getHours() - 3);

// Formateamos para que se vea limpio (Ej: 2026-06-06 10:05:46)
var fechaLocal = fecha_actual.toISOString().replace(/T/, ' ').replace(/\..+/, '');

texto_mensaje += "\n\n📅 Fecha/Hora (ARG): " + fechaLocal;
texto_mensaje += "\n🌐 Origen: Modbus OSM27 - IPSEP (UNRC)";

// 5. Empaquetamos para Telegram
var telegramPayload = {
    "chat_id": "6174555600", 
    "text": texto_mensaje
};

return {msg: telegramPayload, metadata: metadata, msgType: msgType};

// 1. Cazador de variables
var tipo_falla = msg.type || msg.name || metadata.alarmType || metadata.type || "Anomalía No Identificada";

// 2. Paleta de colores y variables SCADA
var color_alerta = "#d9534f"; // Rojo por defecto
var texto_severidad = "CRÍTICA";
var detalle_tecnico = "Se ha registrado un evento anómalo en el equipo OSM27.";

// 3. Switch de clasificación de estados
switch (tipo_falla) {
    case "Aviso de Equipo Cerrado":
        color_alerta = "#28a745"; // Verde
        texto_severidad = "NORMALIZADO";
        detalle_tecnico = "El circuito principal ha sido cerrado y re-energizado correctamente.";
        break;

    case "Aviso de Equipo Abierto":
        color_alerta = "#ff9800"; // Naranja
        texto_severidad = "ADVERTENCIA / MANTENIMIENTO";
        detalle_tecnico = "El reconectador ha abierto sus contactos. La línea se encuentra desenergizada.";
        break;

    case "Alarma de Cortocircuito":
        color_alerta = "#d9534f"; // Rojo
        texto_severidad = "CRÍTICA (ANSI 50/51)";
        detalle_tecnico = "Se ha detectado una sobrecorriente por encima de los 300A nominales.";
        break;

    case "Alarma de SAG":
        color_alerta = "#f39c12"; // Amarillo
        texto_severidad = "CALIDAD DE RED";
        detalle_tecnico = "Hundimiento de tensión (SAG). Voltaje RMS < 11.22 kV.";
        break;

    case "Alarma de Bloqueo":
        color_alerta = "#8b0000"; // Bordó
        texto_severidad = "BLOQUEO TOTAL (ANSI 79)";
        detalle_tecnico = "Falla permanente. El equipo superó los reintentos automáticos. Requiere RESET manual.";
        break;
}

// 4. Parche horario (UTC-3 ARG)
var fecha_actual = new Date();
fecha_actual.setHours(fecha_actual.getHours() - 3);
var fechaLocal = fecha_actual.toISOString().replace(/T/, ' ').replace(/\..+/, '');

// 5. Maquetación del cuerpo del correo en HTML industrial
var html_body = '<div style="font-family: Arial, sans-serif; border: 2px solid ' + color_alerta + '; padding: 20px; border-radius: 5px; max-width: 600px;">' +
    '<h2 style="color: ' + color_alerta + '; margin-top: 0;">⚠️ SCADA IPSEP - Reporte de Red</h2>' +
    '<p>Se ha registrado un cambio de estado en el reconectador <strong>OSM27</strong> del campus UNRC.</p>' +
    '<table style="width: 100%; border-collapse: collapse; margin: 15px 0;">' +
        '<tr style="background-color: #f8f9fa;">' +
            '<th style="padding: 8px; border: 1px solid #dee2e6; text-align: left;">Parámetro</th>' +
            '<th style="padding: 8px; border: 1px solid #dee2e6; text-align: left;">Detalle</th>' +
        '</tr>' +
        '<tr>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;"><strong>Evento:</strong></td>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6; font-weight: bold;">' + tipo_falla + '</td>' +
        '</tr>' +
        '<tr>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;"><strong>Severidad:</strong></td>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6; color: ' + color_alerta + '; font-weight: bold;">' + texto_severidad + '</td>' +
        '</tr>' +
        '<tr>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;"><strong>Diagnóstico:</strong></td>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;">' + detalle_tecnico + '</td>' +
        '</tr>' +
        '<tr>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;"><strong>Fecha/Hora (ARG):</strong></td>' +
            '<td style="padding: 8px; border: 1px solid #dee2e6;">' + fechaLocal + '</td>' +
        '</tr>' +
    '</table>' +
    '<p style="font-size: 12px; color: #6c757d; margin-top: 20px;">' +
        'Este es un aviso automático generado por el Gateway Modbus/TCP. No responder.' +
    '</p>' +
'</div>';

// 6. Inyección en Metadata (El motor de plantillas de TB lee de aquí)
metadata.email_from = "tenant@thingsboard.org";
metadata.email_to = "aldair.moyano.97@gmail.com"; // 👈 Tu correo real
metadata.email_subject = "📡 Alerta SCADA OSM27: " + tipo_falla;
metadata.email_body = html_body;

// Retorno empaquetado
return {
    msg: msg,             // Dejamos el payload original intacto
    metadata: metadata,   // Enviamos la metadata enriquecida
    msgType: msgType
};

// Si se detecta el circuito abierto, enviamos "true" para crear la alarma
if (msg.estado_abierto === true) {
    return true;
}

if (msg.estado_cerrado === true) {
    return false;
}
// En cualquier otro caso (lockout es false), aseguramos la limpieza
return false;

